            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTimeOffset(2026, 5, 21, 16, 45, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 24, 8, 30, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 24, 11, 22, 0, TimeSpan.FromHours(-7)) },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 1, 15, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTimeOffset(2026, 5, 25, 7, 0, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "Awaiting pickup", Location = "Dallas, TX", Timestamp = new DateTimeOffset(2026, 5, 25, 7, 5, 0, TimeSpan.FromHours(-5)) },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
